-- math: Proportions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Proportions", "body": "A proportion sets two ratios equal. Cross-multiply to solve for the unknown."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Solve the proportion:  3/6 = 15/x .  x = ?\n\nThe answer is \"30\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Solve the proportion:  4/5 = 24/x .  x = ?\n\nThe answer is \"30\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Solve the proportion:  5/6 = 15/x .  x = ?\n\nThe answer is \"18\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Solve the proportion:  2/9 = 8/x .  x = ?\n\nThe answer is 36."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Solve the proportion:  5/8 = 20/x .  x = ?\n\nThe answer is 32."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Solve the proportion:  2/5 = 12/x .  x = ?\n\nThe answer is 30."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Proportions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$proportions$tl$ and t.grade_level = 7);

-- math: Unit Rates
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Unit Rates", "body": "A unit rate gives the amount per single unit, like miles per hour or cost per item."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A car goes 14 miles in 2 hours. What is the speed in miles per hour?\n\nThe answer is \"7\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A car goes 30 miles in 5 hours. What is the speed in miles per hour?\n\nThe answer is \"6\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A car goes 48 miles in 4 hours. What is the speed in miles per hour?\n\nThe answer is \"12\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  A car goes 125 miles in 5 hours. What is the speed in miles per hour?\n\nThe answer is 25."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  A car goes 85 miles in 5 hours. What is the speed in miles per hour?\n\nThe answer is 17."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  A car goes 140 miles in 5 hours. What is the speed in miles per hour?\n\nThe answer is 28."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Unit Rates! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$unit-rates$tl$ and t.grade_level = 7);

