where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$combining-like-terms$tl$ and t.grade_level = 7);

-- math: Area & Circumference of Circles
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Area & Circumference of Circles", "body": "Area = pi x r x r; circumference = 2 x pi x r. Use 3.14 as an estimate for pi."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Find the AREA of a circle with radius 4. Use 3.14 for pi. (area = pi x r x r)\n\nThe answer is \"50.24\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Find the AREA of a circle with radius 5. Use 3.14 for pi. (area = pi x r x r)\n\nThe answer is \"78.5\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Find the AREA of a circle with radius 4. Use 3.14 for pi. (area = pi x r x r)\n\nThe answer is \"50.24\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Find the AREA of a circle with radius 2. Use 3.14 for pi. (area = pi x r x r)", "choices": [{"id": "a", "label": "25.12"}, {"id": "b", "label": "6.28"}, {"id": "c", "label": "4"}, {"id": "d", "label": "12.56"}], "answer": "d", "explanation": "Yes! The answer is \"12.56\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Find the AREA of a circle with radius 5. Use 3.14 for pi. (area = pi x r x r)", "choices": [{"id": "a", "label": "78.5"}, {"id": "b", "label": "25"}, {"id": "c", "label": "15.7"}, {"id": "d", "label": "157"}], "answer": "a", "explanation": "Yes! The answer is \"78.5\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Find the CIRCUMFERENCE of a circle with radius 7. Use 3.14 for pi. (C = 2 x pi x r)", "choices": [{"id": "a", "label": "14"}, {"id": "b", "label": "153.86"}, {"id": "c", "label": "43.96"}, {"id": "d", "label": "21.98"}], "answer": "c", "explanation": "Yes! The answer is \"43.96\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Area & Circumference of Circles! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
