update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Photosynthesis & Respiration", "body": "Plants make food in photosynthesis; cells release that energy in respiration."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  In photosynthesis, plants use sunlight, water, and carbon dioxide to make:\n\nThe answer is \"glucose (sugar) and oxygen\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which gas do plants take IN during photosynthesis?\n\nThe answer is \"carbon dioxide\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which gas do plants RELEASE during photosynthesis?\n\nThe answer is \"oxygen\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Cellular respiration releases energy from food using:", "choices": [{"id": "a", "label": "sunlight"}, {"id": "b", "label": "soil"}, {"id": "c", "label": "nitrogen"}, {"id": "d", "label": "oxygen"}], "answer": "d", "explanation": "Yes! The answer is \"oxygen\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Respiration produces carbon dioxide, water, and:", "choices": [{"id": "a", "label": "sugar"}, {"id": "b", "label": "energy (ATP)"}, {"id": "c", "label": "soil"}, {"id": "d", "label": "sunlight"}], "answer": "b", "explanation": "Yes! The answer is \"energy (ATP)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Photosynthesis happens in plant cell parts called:", "choices": [{"id": "a", "label": "mitochondria"}, {"id": "b", "label": "nuclei"}, {"id": "c", "label": "chloroplasts"}, {"id": "d", "label": "ribosomes"}], "answer": "c", "explanation": "Yes! The answer is \"chloroplasts\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Photosynthesis & Respiration! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
