-- science: Matter & Energy in Ecosystems
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Matter & Energy in Ecosystems", "body": "Energy flows one way and is lost as heat; matter is recycled through ecosystems."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Energy enters most ecosystems as:\n\nThe answer is \"sunlight\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Matter such as carbon and water is:\n\nThe answer is \"recycled through the ecosystem\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Energy moves through an ecosystem and is mostly lost as:\n\nThe answer is \"heat\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Decomposers return nutrients (matter) to the:", "choices": [{"id": "a", "label": "Sun"}, {"id": "b", "label": "atmosphere only"}, {"id": "c", "label": "ocean only"}, {"id": "d", "label": "soil"}], "answer": "d", "explanation": "Yes! The answer is \"soil\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An energy pyramid shows that available energy decreases as you go:", "choices": [{"id": "a", "label": "down the levels"}, {"id": "b", "label": "into the Sun"}, {"id": "c", "label": "up the levels"}, {"id": "d", "label": "sideways"}], "answer": "c", "explanation": "Yes! The answer is \"up the levels\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "About how much energy passes to the next trophic level?", "choices": [{"id": "a", "label": "roughly 10%"}, {"id": "b", "label": "100%"}, {"id": "c", "label": "90%"}, {"id": "d", "label": "0%"}], "answer": "a", "explanation": "Yes! The answer is \"roughly 10%\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Matter & Energy in Ecosystems! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
