-- science: Natural Selection
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Natural Selection", "body": "Helpful inherited traits become more common over generations as organisms survive."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Traits that help an organism survive and reproduce are:\n\nThe answer is \"favored by natural selection\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Differences among individuals of a species are called:\n\nThe answer is \"variation\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Organisms with helpful traits are more likely to:\n\nThe answer is \"survive and have offspring\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Over many generations, helpful traits become:", "choices": [{"id": "a", "label": "less common"}, {"id": "b", "label": "more common"}, {"id": "c", "label": "random"}, {"id": "d", "label": "extinct"}], "answer": "b", "explanation": "Yes! The answer is \"more common\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A heritable trait that improves survival is an:", "choices": [{"id": "a", "label": "accident"}, {"id": "b", "label": "habitat"}, {"id": "c", "label": "fossil"}, {"id": "d", "label": "adaptation"}], "answer": "d", "explanation": "Yes! The answer is \"adaptation\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Natural selection acts on traits that are:", "choices": [{"id": "a", "label": "learned in life"}, {"id": "b", "label": "inherited"}, {"id": "c", "label": "painted on"}, {"id": "d", "label": "temporary"}], "answer": "b", "explanation": "Yes! The answer is \"inherited\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Natural Selection! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
