-- science: Heredity & Genes
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Heredity & Genes", "body": "Genes made of DNA carry traits from parents to offspring; alleles can be dominant or recessive."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The molecule that carries genetic information is:\n\nThe answer is \"DNA\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A segment of DNA that codes for a trait is a:\n\nThe answer is \"gene\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Offspring inherit genes from:\n\nThe answer is \"both parents\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Different versions of a gene are called:", "choices": [{"id": "a", "label": "cells"}, {"id": "b", "label": "proteins"}, {"id": "c", "label": "organs"}, {"id": "d", "label": "alleles"}], "answer": "d", "explanation": "Yes! The answer is \"alleles\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A trait that is expressed when at least one allele is present is:", "choices": [{"id": "a", "label": "recessive"}, {"id": "b", "label": "dominant"}, {"id": "c", "label": "blended"}, {"id": "d", "label": "extinct"}], "answer": "b", "explanation": "Yes! The answer is \"dominant\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A trait shown only when both alleles match is:", "choices": [{"id": "a", "label": "dominant"}, {"id": "b", "label": "mutated"}, {"id": "c", "label": "recessive"}, {"id": "d", "label": "learned"}], "answer": "c", "explanation": "Yes! The answer is \"recessive\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Heredity & Genes! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
