update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Chemical Reactions", "body": "Reactions rearrange atoms to form new substances while conserving mass."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  In a chemical reaction, the starting substances are the:\n\nThe answer is \"reactants\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The new substances formed are the:\n\nThe answer is \"products\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A chemical reaction forms substances with:\n\nThe answer is \"new properties\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In any reaction, the total mass of reactants equals the total mass of:", "choices": [{"id": "a", "label": "nothing"}, {"id": "b", "label": "products"}, {"id": "c", "label": "the catalyst"}, {"id": "d", "label": "the gas only"}], "answer": "b", "explanation": "Yes! The answer is \"products\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "This equality of mass is the law of:", "choices": [{"id": "a", "label": "gravity"}, {"id": "b", "label": "conservation of mass"}, {"id": "c", "label": "motion"}, {"id": "d", "label": "reflection"}], "answer": "b", "explanation": "Yes! The answer is \"conservation of mass\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Signs of a chemical change include a color change, gas, light, or:", "choices": [{"id": "a", "label": "a new shape only"}, {"id": "b", "label": "temperature change"}, {"id": "c", "label": "melting only"}, {"id": "d", "label": "dissolving only"}], "answer": "b", "explanation": "Yes! The answer is \"temperature change\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Chemical Reactions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
