update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Atoms & the Periodic Table", "body": "Atoms are made of protons, neutrons, and electrons; the periodic table organizes the elements."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The smallest unit of an element is an:\n\nThe answer is \"atom\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The center of an atom is the:\n\nThe answer is \"nucleus\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Positively charged particles in the nucleus are:\n\nThe answer is \"protons\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Particles in the nucleus with no charge are:", "choices": [{"id": "a", "label": "protons"}, {"id": "b", "label": "neutrons"}, {"id": "c", "label": "electrons"}, {"id": "d", "label": "photons"}], "answer": "b", "explanation": "Yes! The answer is \"neutrons\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Negatively charged particles outside the nucleus are:", "choices": [{"id": "a", "label": "electrons"}, {"id": "b", "label": "protons"}, {"id": "c", "label": "neutrons"}, {"id": "d", "label": "atoms"}], "answer": "a", "explanation": "Yes! The answer is \"electrons\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The number of protons in an atom is its:", "choices": [{"id": "a", "label": "mass number"}, {"id": "b", "label": "atomic number"}, {"id": "c", "label": "charge"}, {"id": "d", "label": "weight"}], "answer": "b", "explanation": "Yes! The answer is \"atomic number\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Atoms & the Periodic Table! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
