-- science: Newton's Laws of Motion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Newton's Laws of Motion", "body": "Newton's three laws describe inertia, force = mass x acceleration, and action-reaction."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An object stays at rest or in motion unless acted on by a force. This is:\n\nThe answer is \"Newton's first law (inertia)\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The resistance of an object to a change in motion is:\n\nThe answer is \"inertia\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Force equals mass times acceleration is:\n\nThe answer is \"Newton's second law\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "For every action there is an equal and opposite reaction is:", "choices": [{"id": "a", "label": "the first law"}, {"id": "b", "label": "the second law"}, {"id": "c", "label": "Newton's third law"}, {"id": "d", "label": "inertia"}], "answer": "c", "explanation": "Yes! The answer is \"Newton's third law\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "If mass stays the same and force increases, acceleration:", "choices": [{"id": "a", "label": "decreases"}, {"id": "b", "label": "increases"}, {"id": "c", "label": "stays zero"}, {"id": "d", "label": "reverses time"}], "answer": "b", "explanation": "Yes! The answer is \"increases\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A heavier object needs ____ force to reach the same acceleration as a lighter one.", "choices": [{"id": "a", "label": "less"}, {"id": "b", "label": "no"}, {"id": "c", "label": "negative"}, {"id": "d", "label": "more"}], "answer": "d", "explanation": "Yes! The answer is \"more\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Newton's Laws of Motion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
