update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Energy & Heat", "body": "Energy changes form and is conserved; heat moves by conduction, convection, and radiation."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Heat naturally flows from ____ objects to colder ones.\n\nThe answer is \"hotter\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Thermal energy is related to the motion of an object's:\n\nThe answer is \"particles\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Heat transfer through direct contact is:\n\nThe answer is \"conduction\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Heat transfer by moving fluids (liquids/gases) is:", "choices": [{"id": "a", "label": "conduction"}, {"id": "b", "label": "radiation"}, {"id": "c", "label": "convection"}, {"id": "d", "label": "reflection"}], "answer": "c", "explanation": "Yes! The answer is \"convection\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Heat transfer by waves through space is:", "choices": [{"id": "a", "label": "conduction"}, {"id": "b", "label": "convection"}, {"id": "c", "label": "friction"}, {"id": "d", "label": "radiation"}], "answer": "d", "explanation": "Yes! The answer is \"radiation\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A material that slows heat transfer is an:", "choices": [{"id": "a", "label": "conductor"}, {"id": "b", "label": "catalyst"}, {"id": "c", "label": "insulator"}, {"id": "d", "label": "ion"}], "answer": "c", "explanation": "Yes! The answer is \"insulator\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Energy & Heat! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
