update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Human Impact on Earth", "body": "Human activities affect Earth's systems; conservation and clean energy reduce harm."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Burning fossil fuels increases carbon dioxide, contributing to:\n\nThe answer is \"climate change\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Cutting down forests for land is called:\n\nThe answer is \"deforestation\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A way to reduce waste is to reduce, reuse, and:\n\nThe answer is \"recycle\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Renewable resources include solar, wind, and:", "choices": [{"id": "a", "label": "coal"}, {"id": "b", "label": "oil"}, {"id": "c", "label": "natural gas"}, {"id": "d", "label": "hydropower"}], "answer": "d", "explanation": "Yes! The answer is \"hydropower\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Pollution that runs off into rivers and oceans harms:", "choices": [{"id": "a", "label": "only the air"}, {"id": "b", "label": "aquatic life"}, {"id": "c", "label": "only rocks"}, {"id": "d", "label": "nothing"}], "answer": "b", "explanation": "Yes! The answer is \"aquatic life\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Protecting many species and ecosystems preserves:", "choices": [{"id": "a", "label": "pollution"}, {"id": "b", "label": "traffic"}, {"id": "c", "label": "biodiversity"}, {"id": "d", "label": "erosion"}], "answer": "c", "explanation": "Yes! The answer is \"biodiversity\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Human Impact on Earth! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
