update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Central Idea & Analysis", "body": "Determine a central idea and analyze how details develop it over the text."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The central idea of a text is the:\n\nThe answer is \"most important overall point\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Supporting details function to:\n\nThe answer is \"develop and explain the central idea\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A text may develop its central idea over:\n\nThe answer is \"the whole passage\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Renewable energy is growing because it is cleaner, increasingly cheaper, and more reliable than before.\" The central idea is that renewable energy is:", "choices": [{"id": "a", "label": "expensive"}, {"id": "b", "label": "becoming more practical and appealing"}, {"id": "c", "label": "useless"}, {"id": "d", "label": "disappearing"}], "answer": "b", "explanation": "Yes! The answer is \"becoming more practical and appealing\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To determine a central idea, a strong reader looks for the point that:", "choices": [{"id": "a", "label": "the details all support"}, {"id": "b", "label": "appears only once"}, {"id": "c", "label": "is in the title"}, {"id": "d", "label": "is the shortest"}], "answer": "a", "explanation": "Yes! The answer is \"the details all support\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An objective summary of a central idea avoids the reader's:", "choices": [{"id": "a", "label": "main point"}, {"id": "b", "label": "key details"}, {"id": "c", "label": "personal opinions"}, {"id": "d", "label": "topic"}], "answer": "c", "explanation": "Yes! The answer is \"personal opinions\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Central Idea & Analysis! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
