update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Theme Development", "body": "Trace how a theme develops through the plot and characters' choices."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A theme is a story's:\n\nThe answer is \"central message about life\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Authors develop theme through plot events and:\n\nThe answer is \"character choices\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Theme differs from topic because theme is a:\n\nThe answer is \"complete idea or insight\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Though warned, the crew ignored the storm signs and lost their ship.\" A theme is:", "choices": [{"id": "a", "label": "ignoring wisdom has consequences"}, {"id": "b", "label": "storms are fun"}, {"id": "c", "label": "ships are old"}, {"id": "d", "label": "sailing is easy"}], "answer": "a", "explanation": "Yes! The answer is \"ignoring wisdom has consequences\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A recurring symbol in a story often reinforces the:", "choices": [{"id": "a", "label": "index"}, {"id": "b", "label": "glossary"}, {"id": "c", "label": "theme"}, {"id": "d", "label": "page count"}], "answer": "c", "explanation": "Yes! The answer is \"theme\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To trace theme development, note how it appears:", "choices": [{"id": "a", "label": "only at the start"}, {"id": "b", "label": "across the whole text"}, {"id": "c", "label": "in the title only"}, {"id": "d", "label": "never"}], "answer": "b", "explanation": "Yes! The answer is \"across the whole text\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Theme Development! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
