-- reading: Objective Summary
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Objective Summary", "body": "Summarize a text's central idea and key points objectively, without opinion."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An objective summary should remain:\n\nThe answer is \"neutral and factual\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A summary is ____ than the original.\n\nThe answer is \"shorter\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A good summary captures the central idea and the:\n\nThe answer is \"most important details\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Summaries should be written in:", "choices": [{"id": "a", "label": "the author's exact words"}, {"id": "b", "label": "code"}, {"id": "c", "label": "your own words"}, {"id": "d", "label": "emojis"}], "answer": "c", "explanation": "Yes! The answer is \"your own words\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What should be LEFT OUT of an objective summary?", "choices": [{"id": "a", "label": "the main idea"}, {"id": "b", "label": "key points"}, {"id": "c", "label": "your personal reaction"}, {"id": "d", "label": "the topic"}], "answer": "c", "explanation": "Yes! The answer is \"your personal reaction\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Narrative summaries keep events in:", "choices": [{"id": "a", "label": "logical order"}, {"id": "b", "label": "random order"}, {"id": "c", "label": "reverse only"}, {"id": "d", "label": "no order"}], "answer": "a", "explanation": "Yes! The answer is \"logical order\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Objective Summary! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$summarizing$tl$ and t.grade_level = 7);

-- reading: Textual Evidence & Inference
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Textual Evidence & Inference", "body": "Cite specific evidence to support both explicit answers and inferences."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Textual evidence is information taken ____ from the text.\n\nThe answer is \"directly\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  To support an inference, you must cite:\n\nThe answer is \"evidence from the text\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Strong evidence is both relevant and:\n\nThe answer is \"accurate (truly in the text)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Quotation marks indicate words that are the:", "choices": [{"id": "a", "label": "your words"}, {"id": "b", "label": "a summary"}, {"id": "c", "label": "author's exact words"}, {"id": "d", "label": "a title"}], "answer": "c", "explanation": "Yes! The answer is \"author's exact words\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which best supports the claim 'the character felt anxious'?", "choices": [{"id": "a", "label": "The book is long."}, {"id": "b", "label": "It was Friday."}, {"id": "c", "label": "'Her hands trembled and her voice shook.'"}, {"id": "d", "label": "The cover is red."}], "answer": "c", "explanation": "Yes! The answer is \"'Her hands trembled and her voice shook.'\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When asked 'how do you know?', a strong reader:", "choices": [{"id": "a", "label": "guesses"}, {"id": "b", "label": "ignores the text"}, {"id": "c", "label": "points to text evidence"}, {"id": "d", "label": "changes topic"}], "answer": "c", "explanation": "Yes! The answer is \"points to text evidence\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Textual Evidence & Inference! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
