update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Author's Purpose & Perspective", "body": "Analyze an author's purpose, perspective, and how word choice reveals it."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An author's purpose may be to inform, entertain, or:\n\nThe answer is \"persuade\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  An author's perspective is their:\n\nThe answer is \"attitude toward the topic\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An editorial mainly expresses the writer's:\n\nThe answer is \"opinion\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Loaded or emotional word choices reveal the author's:", "choices": [{"id": "a", "label": "page number"}, {"id": "b", "label": "font"}, {"id": "c", "label": "binding"}, {"id": "d", "label": "bias / perspective"}], "answer": "d", "explanation": "Yes! The answer is \"bias / perspective\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A text presenting only one side of an issue is likely:", "choices": [{"id": "a", "label": "objective"}, {"id": "b", "label": "biased"}, {"id": "c", "label": "fictional"}, {"id": "d", "label": "a poem"}], "answer": "b", "explanation": "Yes! The answer is \"biased\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To find an author's purpose, ask:", "choices": [{"id": "a", "label": "how long is it?"}, {"id": "b", "label": "why did they write this?"}, {"id": "c", "label": "who printed it?"}, {"id": "d", "label": "what font?"}], "answer": "b", "explanation": "Yes! The answer is \"why did they write this?\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Author's Purpose & Perspective! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
