update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Word Meaning & Connotation", "body": "Distinguish denotation from connotation and use clues, roots, and affixes for meaning."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A word's denotation is its:\n\nThe answer is \"dictionary meaning\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A word's connotation is the:\n\nThe answer is \"feeling or association it carries\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  'Thrifty' and 'cheap' have similar denotations but different:\n\nThe answer is \"connotations\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word has a more POSITIVE connotation?", "choices": [{"id": "a", "label": "scrawny"}, {"id": "b", "label": "skinny"}, {"id": "c", "label": "bony"}, {"id": "d", "label": "slender"}], "answer": "d", "explanation": "Yes! The answer is \"slender\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word has a more NEGATIVE connotation?", "choices": [{"id": "a", "label": "determined"}, {"id": "b", "label": "persistent"}, {"id": "c", "label": "firm"}, {"id": "d", "label": "stubborn"}], "answer": "d", "explanation": "Yes! The answer is \"stubborn\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The aroma of bread filled the kitchen.\" \"Aroma\" has a ____ connotation.", "choices": [{"id": "a", "label": "negative"}, {"id": "b", "label": "positive"}, {"id": "c", "label": "neutral only"}, {"id": "d", "label": "no"}], "answer": "b", "explanation": "Yes! The answer is \"positive\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Word Meaning & Connotation! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
