update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Comparing Authors & Accounts", "body": "Compare how different authors present the same topic or event."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Comparing two texts on a topic reveals their different:\n\nThe answer is \"approaches and viewpoints\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A memoir and a news article on the same event differ most in:\n\nThe answer is \"perspective and tone\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Two authors may share facts yet reach different:\n\nThe answer is \"conclusions\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Reading multiple sources helps a reader:", "choices": [{"id": "a", "label": "learn less"}, {"id": "b", "label": "ignore facts"}, {"id": "c", "label": "form a fuller, balanced view"}, {"id": "d", "label": "memorize fonts"}], "answer": "c", "explanation": "Yes! The answer is \"form a fuller, balanced view\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A primary source is an account from:", "choices": [{"id": "a", "label": "someone who experienced the event"}, {"id": "b", "label": "a later textbook only"}, {"id": "c", "label": "fiction always"}, {"id": "d", "label": "an unrelated topic"}], "answer": "a", "explanation": "Yes! The answer is \"someone who experienced the event\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A secondary source typically:", "choices": [{"id": "a", "label": "is always firsthand"}, {"id": "b", "label": "analyzes events after the fact"}, {"id": "c", "label": "is fiction"}, {"id": "d", "label": "has no facts"}], "answer": "b", "explanation": "Yes! The answer is \"analyzes events after the fact\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Comparing Authors & Accounts! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
